import{_ as t,o,c as i,a8 as a}from"./chunks/framework.DvHWw5tv.js";const m=JSON.parse('{"title":"useStyleComputed","description":"","frontmatter":{},"headers":[],"relativePath":"en/design/hooks/useStyle.md","filePath":"en/design/hooks/useStyle.md"}'),n={name:"en/design/hooks/useStyle.md"};function s(l,e,r,d,c,p){return o(),i("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1776410922000"},[...e[0]||(e[0]=[a('<h1 id="usestylecomputed" tabindex="-1">useStyleComputed <a class="header-anchor" href="#usestylecomputed" aria-label="Permalink to “useStyleComputed”">​</a></h1><h2 id="dynamic-style-computation-hook" tabindex="-1">Dynamic Style Computation Hook <a class="header-anchor" href="#dynamic-style-computation-hook" aria-label="Permalink to “Dynamic Style Computation Hook”">​</a></h2><h3 id="pain-points" tabindex="-1">Pain Points <a class="header-anchor" href="#pain-points" aria-label="Permalink to “Pain Points”">​</a></h3><p>Another high-frequency repetitive task in UI component development is dynamically generating inline styles based on props. Common scenarios include:</p><ul><li><code>size=&quot;large&quot;</code> → need to set larger <code>font-size</code>, <code>padding</code>, etc.</li><li><code>width={200}</code> or <code>width=&quot;200px&quot;</code> → need to correctly convert to pixel values</li><li>Components need uniform injection of CSS variables (e.g., <code>--primary-color</code>)</li><li>Certain styles require complex combination logic (e.g., computing <code>border-radius</code> from multiple props)</li></ul><p>Manually constructing style objects in templates or setup leads to redundant code and common pitfalls:</p><ul><li>Inconsistent unit handling (numbers not appended with <code>px</code>)</li><li>Missing type checks</li><li>Scattered CSS variable management</li><li>Difficult-to-extend custom style logic</li></ul><h2 id="design-goals" tabindex="-1">Design Goals <a class="header-anchor" href="#design-goals" aria-label="Permalink to “Design Goals”">​</a></h2><p>The goal of <code>useStyleComputed</code> is to <strong>provide a unified, type-safe, and configurable inline style computation mechanism</strong>, completely stripping all style-related logic from components and allowing them to focus solely on structure and behavior.</p><h2 id="core-features" tabindex="-1">Core Features <a class="header-anchor" href="#core-features" aria-label="Permalink to “Core Features”">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td><strong>Reactive Output</strong></td><td>Returns <code>ComputedRef&lt;CSSProperties&gt;</code>, automatically updating the style object with prop changes</td></tr><tr><td><strong>Prop-to-Style Mapping</strong></td><td>Maps props directly to CSS properties via <code>propToStyleMap</code>, with automatic <code>px</code> addition for common dimension properties</td></tr><tr><td><strong>Intelligent Unit Handling</strong></td><td>For properties like <code>fontSize</code>, <code>width</code>, <code>height</code>, automatically converts numbers to <code>px</code> strings</td></tr><tr><td><strong>CSS Variable Support</strong></td><td>Uniformly injects custom CSS variables via <code>cssVariables</code>, facilitating theme system usage</td></tr><tr><td><strong>Custom Extension</strong></td><td><code>customStyleLogic</code> callback allows injection of complex style computation logic (e.g., multi-prop combinations)</td></tr><tr><td><strong>Type Safe</strong></td><td>Generic <code>&lt;T&gt;</code> strongly binds to component props, providing complete TypeScript IntelliSense</td></tr><tr><td><strong>Clear Boundaries</strong></td><td>Only responsible for computing style objects; does not deal with class names, DOM operations, or media queries</td></tr></tbody></table><h2 id="design-value" tabindex="-1">Design Value <a class="header-anchor" href="#design-value" aria-label="Permalink to “Design Value”">​</a></h2><p><code>useStyleComputed</code> and <code>useClassComputed</code> form a dual approach for class names and inline styles:</p><ul><li><code>useClassComputed</code> handles structured, theme-overridable BEM class names (main force of the presentation layer)</li><li><code>useStyleComputed</code> handles dynamic, precise inline styles that are difficult to achieve with class names (logic layer supplement)</li></ul><p>Through this Hook, the entire component library achieves:</p><ul><li>Highly centralized style logic, avoiding inconsistencies caused by scattering across components</li><li>Uniform unit and type handling, eliminating low-level errors</li><li>Standardized CSS variable injection for deep integration of theme system and dynamic styles</li><li>Easy extension of complex style combinations without polluting component core logic</li><li>Extremely clean component templates requiring only a single <code>:style</code> binding</li></ul>',16)])])}const g=t(n,[["render",s]]);export{m as __pageData,g as default};
